// Calculate date ranges for comparisons
const now = new Date();

// This week (past 7 days)
const thisWeekEnd = new Date(now);
const thisWeekStart = new Date(now);
thisWeekStart.setDate(thisWeekStart.getDate() - 7);

// Previous week (8-14 days ago)
const prevWeekEnd = new Date(thisWeekStart);
const prevWeekStart = new Date(prevWeekEnd);
prevWeekStart.setDate(prevWeekStart.getDate() - 7);

// Same week last year
const lastYearEnd = new Date(now);
lastYearEnd.setFullYear(lastYearEnd.getFullYear() - 1);
const lastYearStart = new Date(lastYearEnd);
lastYearStart.setDate(lastYearStart.getDate() - 7);

return [
  {
    json: {
      thisWeek: {
        start: thisWeekStart.getTime(),
        end: thisWeekEnd.getTime(),
        label: `${thisWeekStart.toLocaleDateString()} - ${thisWeekEnd.toLocaleDateString()}`
      },
      prevWeek: {
        start: prevWeekStart.getTime(),
        end: prevWeekEnd.getTime(),
        label: `${prevWeekStart.toLocaleDateString()} - ${prevWeekEnd.toLocaleDateString()}`
      },
      lastYear: {
        start: lastYearStart.getTime(),
        end: lastYearEnd.getTime(),
        label: `${lastYearStart.toLocaleDateString()} - ${lastYearEnd.toLocaleDateString()}`
      },
      reportDate: now.toLocaleDateString('en-US', { 
        weekday: 'long', 
        year: 'numeric', 
        month: 'long', 
        day: 'numeric' 
      })
    }
  }
];

// Get all the data from previous nodes
const dateRanges = $node["Calculate Date Ranges"].json;
const thisWeekContacts = $node["Get This Week Contacts"].json;
const prevWeekContacts = $node["Get Previous Week Contacts"].json;
const lastYearContacts = $node["Get Last Year Contacts"].json;
const thisWeekDeals = $node["Get This Week Deals"].json;
const prevWeekDeals = $node["Get Previous Week Deals"].json;
const lastYearDeals = $node["Get Last Year Deals"].json;

// Helper function to filter for MQL list membership
function filterForMQLList(contacts, listId = "873") {
  // Since we can't filter by list in search API, we'll count all contacts
  // In a real scenario, you'd need to check each contact's list membership
  // For now, we'll use total contacts as proxy
  return contacts.results || [];
}

// Helper function to calculate percentage change
function calculateChange(current, previous) {
  if (previous === 0) return current > 0 ? 100 : 0;
  return ((current - previous) / previous) * 100;
}

// Helper function to calculate total deal value
function calculateDealValue(deals) {
  const results = deals.results || [];
  return results.reduce((sum, deal) => {
    const amount = parseFloat(deal.properties?.amount || 0);
    return sum + amount;
  }, 0);
}

// Calculate contact metrics
const thisWeekContactsCount = (thisWeekContacts.results || []).length;
const prevWeekContactsCount = (prevWeekContacts.results || []).length;
const lastYearContactsCount = (lastYearContacts.results || []).length;

const contactsWoWChange = calculateChange(thisWeekContactsCount, prevWeekContactsCount);
const contactsYoYChange = calculateChange(thisWeekContactsCount, lastYearContactsCount);

// Calculate deal metrics
const thisWeekDealsCount = (thisWeekDeals.results || []).length;
const prevWeekDealsCount = (prevWeekDeals.results || []).length;
const lastYearDealsCount = (lastYearDeals.results || []).length;

const thisWeekDealValue = calculateDealValue(thisWeekDeals);
const prevWeekDealValue = calculateDealValue(prevWeekDeals);
const lastYearDealValue = calculateDealValue(lastYearDeals);

const dealsWoWChange = calculateChange(thisWeekDealsCount, prevWeekDealsCount);
const dealsYoYChange = calculateChange(thisWeekDealsCount, lastYearDealsCount);

const dealValueWoWChange = calculateChange(thisWeekDealValue, prevWeekDealValue);
const dealValueYoYChange = calculateChange(thisWeekDealValue, lastYearDealValue);

// Format currency
function formatCurrency(amount) {
  return '$' + amount.toLocaleString('en-US', { minimumFractionDigits: 0, maximumFractionDigits: 0 });
}

// Format percentage
function formatPercent(value) {
  const sign = value >= 0 ? '+' : '';
  return sign + value.toFixed(1) + '%';
}

// Build the report
const report = `
📊 vFAIRS WEEKLY HUBSPOT REPORT
${'='.repeat(50)}
Report Date: ${dateRanges.reportDate}
Period: ${dateRanges.thisWeek.label}
${'='.repeat(50)}

📧 NEW LEADS (CONTACTS)
${'-'.repeat(50)}
This Week:     ${thisWeekContactsCount} leads
Previous Week: ${prevWeekContactsCount} leads
Same Week 2025: ${lastYearContactsCount} leads

Week-over-Week: ${formatPercent(contactsWoWChange)} ${contactsWoWChange >= 0 ? '📈' : '📉'}
Year-over-Year: ${formatPercent(contactsYoYChange)} ${contactsYoYChange >= 0 ? '📈' : '📉'}

💼 NEW DEALS
${'-'.repeat(50)}
This Week:     ${thisWeekDealsCount} deals
Previous Week: ${prevWeekDealsCount} deals  
Same Week 2025: ${lastYearDealsCount} deals

Week-over-Week: ${formatPercent(dealsWoWChange)} ${dealsWoWChange >= 0 ? '📈' : '📉'}
Year-over-Year: ${formatPercent(dealsYoYChange)} ${dealsYoYChange >= 0 ? '📈' : '📉'}

💰 DEAL VALUE
${'-'.repeat(50)}
This Week:     ${formatCurrency(thisWeekDealValue)}
Previous Week: ${formatCurrency(prevWeekDealValue)}
Same Week 2025: ${formatCurrency(lastYearDealValue)}

Week-over-Week: ${formatPercent(dealValueWoWChange)} ${dealValueWoWChange >= 0 ? '📈' : '📉'}
Year-over-Year: ${formatPercent(dealValueYoYChange)} ${dealValueYoYChange >= 0 ? '📈' : '📉'}

${'='.repeat(50)}

🎯 KEY INSIGHTS:
• Average deal size this week: ${formatCurrency(thisWeekDealsCount > 0 ? thisWeekDealValue / thisWeekDealsCount : 0)}
• Lead-to-Deal ratio: ${thisWeekContactsCount > 0 ? ((thisWeekDealsCount / thisWeekContactsCount) * 100).toFixed(1) : 0}%
${thisWeekContactsCount > prevWeekContactsCount ? '✅ Lead generation is UP!' : '⚠️ Lead generation needs attention'}
${thisWeekDealValue > prevWeekDealValue ? '✅ Deal value is UP!' : '⚠️ Deal value needs attention'}
`;

return [
  {
    json: {
      report: report,
      data: {
        contacts: {
          thisWeek: thisWeekContactsCount,
          prevWeek: prevWeekContactsCount,
          lastYear: lastYearContactsCount,
          wowChange: contactsWoWChange,
          yoyChange: contactsYoYChange
        },
        deals: {
          count: {
            thisWeek: thisWeekDealsCount,
            prevWeek: prevWeekDealsCount,
            lastYear: lastYearDealsCount,
            wowChange: dealsWoWChange,
            yoyChange: dealsYoYChange
          },
          value: {
            thisWeek: thisWeekDealValue,
            prevWeek: prevWeekDealValue,
            lastYear: lastYearDealValue,
            wowChange: dealValueWoWChange,
            yoyChange: dealValueYoYChange
          }
        },
        dateRanges: dateRanges
      }
    }
  }
];
